async function handleRequest(request) {
    const url = new URL(request.url);

    // Get the service name from the URL path
    let serviceName = url.pathname;
    if (serviceName === '/') {
        return new Response('Hello World', { status: 200 })
    }

    // Forward the request to the internal worker for processing
    const response = await fetch(`https://api.cloudflareworkers.com/internal-worker/${serviceName}`, { method: 'POST' });
    if (response.status !== 200) {
        return new Response(response.statusText, { status: response.status })
    }

    // Return the response from the internal worker
    const contentType = response.headers.get('content-type');
    let body = await response.text();
    return new Response(body, { headers: { 'Content-Type': contentType }, status: 200 });
}